    groups = defaultdict(list)

    # Group results by the specified metadata field
    for result in search_results:
        # Extract metadata field value for grouping
        field_value = result.metadata.get(group_by_field)

        # Handle missing field values by assigning to 'unknown' group
        if field_value is None:
            group_key = 'unknown'
        else:
            group_key = str(field_value)

        groups[group_key].append(result)

    # Calculate statistics for each group
    aggregated_results = {}

    for group_key, results in groups.items():
        group_stats = {}

