        if aggregation_funcs is None:
            # Calculate default statistics: count, average, max, min scores
            if results:
                scores = [r.score for r in results]
                group_stats = {
                    "count": len(results),
                    "avg_score": sum(scores) / len(scores),
                    "max_score": max(scores),
                    "min_score": min(scores)
                }
            else:
                # Handle empty group
                group_stats = {
                    "count": 0,
                    "avg_score": 0.0,
                    "max_score": 0.0,
                    "min_score": 0.0
                }
        else:
            # Apply custom aggregation functions
            for field_name, agg_func in aggregation_funcs.items():
                try:
                    # Extract field values from results for aggregation
                    field_values = []
                    for result in results:
                        # Check both top-level attributes and metadata
                        if hasattr(result, field_name):
                            value = getattr(result, field_name)
                        else:
                            value = result.metadata.get(field_name)

                        if value is not None:
                            field_values.append(value)

                    # Apply aggregation function if we have values
                    if field_values:
                        group_stats[field_name] = agg_func(field_values)
                    else:
                        # Handle case where no valid field values exist
                        group_stats[field_name] = None

                except Exception as e:
                    # Handle errors in aggregation
                    group_stats[field_name] = f"Error: {str(e)}"

        aggregated_results[group_key] = group_stats

    return aggregated_results
